queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?metric_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:metrics_id ?cg . ?child a :Metrics ; p:id ?cg . ?l p:product_manager_id ?pg . ?parent a :Product_Managers ; p:id ?pg . } GROUP BY ?child }
  ?child p:metric_name ?metric_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Product_Managers } }
  FILTER(?nf = ?total)
}

